        public static X509Certificate2 LoadFromStore(StoreName storeName, StoreLocation storeLocation, string thumbprint)
        {
            if (string.IsNullOrWhiteSpace(thumbprint)) throw new ArgumentException("Thumbprint is required.", nameof(thumbprint));

            thumbprint = thumbprint.Replace(" ", "").ToUpperInvariant();

            using var store = new X509Store(storeName, storeLocation);
            store.Open(OpenFlags.ReadOnly);

            var found = store.Certificates.Find(X509FindType.FindByThumbprint, thumbprint, validOnly: false);
            if (found.Count == 0) throw new InvalidOperationException($"Certificate not found. store={storeName}/{storeLocation} thumbprint={thumbprint}");
            return found[0];
        }
    }

